    def kelliste(tu,energu,wqu):
        felfliste=2*((energu*1.602*10**-19)/(scipy.pi))**0.5*(1.38065*10**-23*tu)**(-3/2)*scipy.exp((-energu*1.602*10**-19)/(1.38065*10**-23*tu))*1.602*10**-19*wqu*((2*energu*1.602*10**-19)/(9.10938215*10**-31))**0.5
        kelfliste=scipy.integrate.simps(felfliste,energu)
        return kelfliste
