    def Rind(nu,ngu,teu):
        Rindf=((2*scipy.pi*Nw**2)/(L*omega*epsilon0))*((im*k(nu,ngu,teu)*R*scipy.special.jv(1,k(nu,ngu,teu)*R))/(epsilonp(nu,ngu,teu)*scipy.special.jv(0,k(nu,ngu,teu)*R))).real
